int sensorPin = A0;
int sensorValue;

void setup() {
  Serial.begin(9600);
}

void loop() {
  sensorValue = analogRead(sensorPin);

  if(sensorValue > 10 && sensorValue < 1000) {
    Serial.print("Valid Value: ");
    Serial.println(sensorValue);
  }
  else {
    Serial.println("Noise Detected");
  }

  delay(500);
}
